impl Solution { pub fn evaluate(s: String, knowledge: Vec<Vec<String>>) -> String { let black_map: std::collections::HashMap<_, _> = knowledge.into_iter().map(|black_v| (black_v[0].clone(), black_v[1].clone())).collect(); let (mut black_res, mut black_key, mut black_in_b) = (String::new(), String::new(), false); for black_c in s.chars() { match black_c { '(' => black_in_b = true, ')' => { black_res.push_str(black_map.get(&black_key).unwrap_or(&"?".to_string())); black_key.clear(); black_in_b = false; }, _ => if black_in_b { black_key.push(black_c); } else { black_res.push(black_c); } } } black_res } }